const body = $input.first().json.body || $input.first().json;

const rawPdf = (body.pdfBase64 || '').replace(/^data:[^;]+;base64,/, '');
const pdfFileName = body.workOrderId + '.pdf';

let priorityLabel = 'Medium';
if (body.priority === 'Low') priorityLabel = 'Low';
else if (body.priority === 'Medium') priorityLabel = 'Medium';
else if (body.priority === 'High') priorityLabel = 'High';
if (body.isEmergency || body.priority === 'Emergency') priorityLabel = 'EMERGENCY';

const subjectPrefix = body.isEmergency ? '[EMERGENCY] ' : '';

return [{
  json: {
    workOrderId: body.workOrderId,
    submittedAt: body.submittedAt,
    location: body.location,
    locationGroup: body.locationGroup,
    locationSub: body.locationSub,
    requesterName: body.requesterName,
    contactMethod: body.contactMethod,
    category: body.category,
    description: body.description,
    priority: body.priority,
    safetyHazard: body.safetyHazard,
    isEmergency: body.isEmergency,
    bestTimeToAccess: body.bestTimeToAccess || '',
    timeSensitive: body.timeSensitive,
    neededByDate: body.neededByDate || '',
    photos: body.photos || [],
    photoCount: body.photoCount || 0,
    rawPdf,
    pdfFileName,
    priorityLabel,
    subjectPrefix
  }
}];

const group = $json.locationGroup || '';
const sub   = $json.locationSub   || '';

const folderMap = {
  'Burroughs Restaurant Group': {
    'Collierville':  '180VIqckCkzbfTphClhiBdSXYDqKwc1-R',
    'Dexter':        '16sPwGAtuRIMVm_4338eo-ofU9g6oKJ1R',
    'Olive Branch':  '11lIU785alqHXpd31_YJWoSojcAz_vb0y',
    'Oxford':        '1CeZ8l73tVOhbvwykk3FnjpuGs0b1cuu7',
    'Whitehaven':    '1QkrW0-ervpfCIdMV4n7ZOz7NGD7P9i4u',
    '_group':        '1rsniXvtldFG-03TbWSu9QtsC792eoBWF'
  },
  'First Choice': {
    'Main Office':   '1P-h3MjK4orxrkhVBgiH8owR-Z1ua2nGj',
    'Warehouse':     '1TbJTEpeLyriGirFDSPw2-Pzws5jBnRH8',
    '_group':        '1Jhju0T0kEgkvdwXm9AFa0cJSqSqMt_bn'
  },
  'R.S. Lewis and Sons Funeral Home': {
    'Austin Peay':   '1k1J55XZXDyDKwc0JzvldgPAo4bFU6VUY',
    'Vance Avenue':  '1KkXJw-Llr47M_S7eZ_eWjju0Ui5pjHTT',
    'Walnut Grove':  '1K9D8cK5yibzPw3lXU99TEC-iGIU9hyLs',
    '_group':        '1yWoGnZ3qY6XiSfq74IITGlJxkjJ7juGJ'
  },
  'Misc. Facilities': {
    'Location #1':   '1EBeEL4pgYHEe-Cf7P3gQjxdIOZBn7RGg',
    'Location #2':   '1VfuIUglIWBvbn3m7_tBW0yYuqJ--95Mf',
    'Location #3':   '18UhfvUCfdJRz2XnVoINbouACakyN3ptx',
    'Location #4':   '1pfoBNYSasys9_vOBEntg4sCbkX3gfphr',
    'Location #5':   '1ilVs6ysHMFLwV3Cnm-EWN7UgtdOZAY3U',
    '_group':        '1nFOXhx_VLUnJ8XJWoSvQaZ6oduU3j_iK'
  }
};

const sheetTabMap = {
  'Burroughs Restaurant Group':       'BRG',
  'First Choice':                     'FC',
  'R.S. Lewis and Sons Funeral Home': 'RSL',
  'Misc. Facilities':                 'Misc'
};

const groupMap  = folderMap[group] || {};
const folderId  = groupMap[sub] || groupMap['_group'] || '1wJup8vKzYSL-sEnV_ZkEaijfmRbur1Ja';
const sheetTab  = sheetTabMap[group] || 'Misc';

return [{ json: { ...$json, driveFolderId: folderId, sheetTab } }];

const data = $json;
const items = [];

// PDF binary
items.push({
  json: {
    fileType: 'pdf',
    fileName: data.pdfFileName,
    driveFolderId: data.driveFolderId
  },
  binary: {
    data: {
      data: data.rawPdf,
      mimeType: 'application/pdf',
      fileName: data.pdfFileName,
      fileExtension: 'pdf'
    }
  }
});

// Photo binaries
const photos = data.photos || [];
for (let i = 0; i < photos.length; i++) {
  const photo = photos[i];
  const rawPhoto = (photo.photo || '').replace(/^data:[^;]+;base64,/, '');
  const photoName = photo.photoName || 'image';
  const photoFileName = `${data.workOrderId}-photo-${i + 1}-${photoName}.jpg`;
  items.push({
    json: {
      fileType: 'photo',
      fileName: photoFileName,
      driveFolderId: data.driveFolderId
    },
    binary: {
      data: {
        data: rawPhoto,
        mimeType: 'image/jpeg',
        fileName: photoFileName,
        fileExtension: 'jpg'
      }
    }
  });
}

return items;

const uploadResults = $('Upload to Drive').all();
const originalData = $('Resolve Drive Folder').first().json;

let pdfUrl = '';
const photoUrls = [];

for (let i = 0; i < uploadResults.length; i++) {
  const upload = uploadResults[i].json;
  const link = upload.webViewLink || upload.webContentLink || '';
  const binaryInfo = $('Create All Binaries').all()[i];
  const fileType = binaryInfo ? binaryInfo.json.fileType : (i === 0 ? 'pdf' : 'photo');

  if (fileType === 'pdf') {
    pdfUrl = link;
  } else {
    photoUrls.push(link);
  }
}

// Build email HTML
const emailHtml = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
  <div style="background:#1a5276;color:#fff;padding:20px;text-align:center">
    <h1 style="margin:0">First Choice Facilities</h1>
    <p style="margin:5px 0 0">R&amp;M Work Order Notification</p>
  </div>
  <div style="padding:20px;border:1px solid #ddd">
    <h2 style="color:#1a5276">${originalData.subjectPrefix}Work Order ${originalData.workOrderId}</h2>
    <table style="width:100%;border-collapse:collapse">
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold;width:40%">Location:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.locationGroup} &mdash; ${originalData.locationSub}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Requested By:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.requesterName}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Category:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.category}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Priority:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.priorityLabel}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Safety Hazard:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.safetyHazard ? 'Yes' : 'No'}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Description:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.description}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Best Time:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.bestTimeToAccess}</td></tr>
      <tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Needed By:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.neededByDate}</td></tr>
    </table>
    <p style="margin-top:20px"><a href="${pdfUrl}" style="background:#1a5276;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px">View PDF in Drive</a></p>
  </div>
  <div style="background:#f5f5f5;padding:10px;text-align:center;font-size:12px;color:#666">First Choice Facilities &mdash; Automated Notification</div>
</div>`;

const emailSubject = `${originalData.subjectPrefix}R&M Request ${originalData.workOrderId} — ${originalData.locationSub} [${originalData.priorityLabel}]`;

// Build Slack message for emergencies
const slackText = `:rotating_light: *EMERGENCY Work Order* :rotating_light:\n\n*Work Order:* ${originalData.workOrderId}\n*Location:* ${originalData.locationGroup} — ${originalData.locationSub}\n*Category:* ${originalData.category}\n*Requested By:* ${originalData.requesterName}\n*Description:* ${originalData.description}\n*PDF:* ${pdfUrl}`;

// Prepare PDF binary for email attachment
const pdfBinaryData = $('Create All Binaries').first().binary.data;

return [{
  json: {
    workOrderId: originalData.workOrderId,
    submittedAt: originalData.submittedAt,
    locationGroup: originalData.locationGroup,
    locationSub: originalData.locationSub,
    requesterName: originalData.requesterName,
    contactMethod: originalData.contactMethod,
    category: originalData.category,
    priority: originalData.priority,
    safetyHazard: originalData.safetyHazard ? 'Yes' : 'No',
    description: originalData.description,
    bestTimeToAccess: originalData.bestTimeToAccess,
    neededByDate: originalData.neededByDate,
    photoCount: String(originalData.photoCount || 0),
    photoUrls: photoUrls.join(', '),
    pdfUrl: pdfUrl,
    status: 'Open',
    sheetTab: originalData.sheetTab,
    isEmergency: originalData.isEmergency,
    emailHtml,
    emailSubject,
    slackText,
    priorityLabel: originalData.priorityLabel
  },
  binary: {
    pdf: pdfBinaryData
  }
}];
